#include <stdio.h>
#include <string.h>

int countFlips(const char *s, int n, int startBit) {
    int flips = 0, parity = 0;
    for (int i = 0; i < n; ++i) {
        int cur = (s[i] - '0') ^ parity;
        int desired = (startBit + i) & 1;
        if (cur != desired) {
            ++flips;
            parity ^= 1;
        }
    }
    return flips;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        static char s[200005];
        scanf("%s", s);
        int ans0 = countFlips(s, N, 0);
        int ans1 = countFlips(s, N, 1);
        printf("%d\n", ans0 < ans1 ? ans0 : ans1);
    }
    return 0;
}

